from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
import secrets
import string
import smtplib
from email.mime.multipart import MIMEMultipart
from email.mime.text import MIMEText

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///password_reset.db'
db = SQLAlchemy(app)

class PasswordReset(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(100), unique=True, nullable=False)
    token = db.Column(db.String(50), nullable=False)

@app.route('/reset', methods=['POST'])
def password_reset():
    data = request.json
    if 'email' not in data or 'token' not in data:
        return jsonify({'error': 'Missing required fields'}), 400

    user_email = data['email']
    existing_token = PasswordReset.query.filter_by(email=user_email).first()
    if existing_token and existing_token.token == data['token']:
        # Token is valid, allow password reset
        return jsonify({'message': 'Password reset successful'}), 200

    new_token = ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(50))
    db.session.add(PasswordReset(email=user_email, token=new_token))
    db.session.commit()

    # Send password reset email
    msg = MIMEMultipart()
    msg['From'] = 'your-email@gmail.com'
    msg['To'] = user_email
    msg['Subject'] = 'Password Reset Link'

    body = f'Click this link to reset your password: http://example.com/reset?email={user_email}&token={new_token}'
    msg.attach(MIMEText(body, 'plain'))

    server = smtplib.SMTP('smtp.gmail.com', 587)
    server.starttls()
    server.login(msg['From'], 'your-password')
    text = msg.as_string()
    server.sendmail(msg['From'], msg['To'], text)
    server.quit()

    return jsonify({'message': 'Password reset email sent'}), 200

if __name__ == '__main__':
    with app.app_context():
        db.create_all()
    app.run(debug=True)